using Dalamud.Interface.Components;namespace TidyChat.Settings.Tabs;internal static class GatheringTab{    public static void Draw(Configuration configuration)    {        SettingsTabLayout.DrawTabNote(Languages.GatheringTab_FilteringNote);        SettingsTabLayout.DrawSections(true,            (Languages.GatheringTab_GatheringLocationsDropdownHeader, () => DrawGatheringLocations(configuration)),            (Languages.GatheringTab_AetherialReductionDropdownHeader, () => DrawAetherialReduction(configuration)),            (Languages.GatheringTab_FishingDropdownHeader, () => DrawFishing(configuration)),            (Languages.GatheringTab_ElementalShardsDropdownHeader, () => DrawElementalShards(configuration)),            (Languages.GatheringTab_StellarMissionsDropdownHeader, () => DrawStellarMissions(configuration)));    }    private static void DrawGatheringLocations(Configuration configuration)    {        var showGatheringSenses = configuration.ShowGatheringSenses;        if (ImGui.Checkbox(Languages.GatheringTab_ShowGatheringSensesLabel,                ref showGatheringSenses))        {            configuration.ShowGatheringSenses = showGatheringSenses;            configuration.OnSettingChanged();        }        var showGatheringStartEnd = configuration.ShowGatheringStartEnd;        if (ImGui.Checkbox(Languages.GatheringTab_ShowGatheringStartEnd,                ref showGatheringStartEnd))        {            configuration.ShowGatheringStartEnd = showGatheringStartEnd;            configuration.OnSettingChanged();        }        var showLocationAffects = configuration.ShowLocationAffects;        if (ImGui.Checkbox(Languages.GatheringTab_ShowLocationGatheringEffectMessages,                ref showLocationAffects))        {            configuration.ShowLocationAffects = showLocationAffects;            configuration.OnSettingChanged();        }        var showGatheringYield = configuration.ShowGatheringYield;        if (ImGui.Checkbox(Languages.GatheringTab_HideGatheringYieldLocationMessages,                ref showGatheringYield))        {            configuration.ShowGatheringYield = showGatheringYield;            configuration.OnSettingChanged();        }        var showGatheringAttempts = configuration.ShowGatheringAttempts;        if (ImGui.Checkbox(Languages.GatheringTab_HideGatheringAttemptsLocationMessages,                ref showGatheringAttempts))        {            configuration.ShowGatheringAttempts = showGatheringAttempts;            configuration.OnSettingChanged();        }        var showGatherersBoon = configuration.ShowGatherersBoon;        if (ImGui.Checkbox(Languages.GatheringTab_HideGatheringBoonLocationMessages,                ref showGatherersBoon))        {            configuration.ShowGatherersBoon = showGatherersBoon;            configuration.OnSettingChanged();        }        var showGatheringCollectableObtains = configuration.ShowGatheringCollectableObtains;        if (ImGui.Checkbox(Languages.GatheringTab_ShowGatheringCollectableObtainMessages,                ref showGatheringCollectableObtains))        {            configuration.ShowGatheringCollectableObtains = showGatheringCollectableObtains;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.GatheringTab_ShowGatheringCollectableObtainMessagesHelpMarker);        var showAllOtherGathering = configuration.ShowAllOtherGathering;        if (ImGui.Checkbox(Languages.GatheringTab_ShowAllOtherGathering, ref showAllOtherGathering))        {            configuration.ShowAllOtherGathering = showAllOtherGathering;            configuration.OnSettingChanged();        }        UiHelp.GatheringFilterMarker(Languages.GatheringTab_ShowAllOtherGatheringHelpMarker);        SettingsTabLayout.DrawNestedOptions(configuration.ShowAllOtherGathering, () =>        {            var showGatheringBuff = configuration.ShowGatheringBuffEffectGain;            if (ImGui.Checkbox(Languages.GatheringTab_ShowGatheringBuffEffectGain, ref showGatheringBuff))            {                configuration.ShowGatheringBuffEffectGain = showGatheringBuff;                configuration.OnSettingChanged();            }            UiHelp.GatheringFilterMarker(Languages.GatheringTab_ShowGatheringBuffEffectGainHelpMarker);        });    }    private static void DrawAetherialReduction(Configuration configuration)    {        var showAetherialReductionSands = configuration.ShowAetherialReductionSands;        if (ImGui.Checkbox(Languages.GatheringTab_ShowObtainedSandsFromAetherialReductionMessages,                ref showAetherialReductionSands))        {            configuration.ShowAetherialReductionSands = showAetherialReductionSands;            configuration.OnSettingChanged();        }        var showAetherialReductionSuccess = configuration.ShowAetherialReductionSuccess;        if (ImGui.Checkbox(Languages.GatheringTab_ShowAetherialReductionSuccessMessages,                ref showAetherialReductionSuccess))        {            configuration.ShowAetherialReductionSuccess = showAetherialReductionSuccess;            configuration.OnSettingChanged();        }        var showAetherialReductionMinigame = configuration.ShowAetherialReductionMinigame;        if (ImGui.Checkbox(Languages.GatheringTab_ShowAetherialReductionMinigameMessages,                ref showAetherialReductionMinigame))        {            configuration.ShowAetherialReductionMinigame = showAetherialReductionMinigame;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.GatheringTab_ShowAetherialReductionMinigameMessagesHelpMarker);    }    private static void DrawFishing(Configuration configuration)    {        var showCaughtFish = configuration.ShowCaughtFish;        if (ImGui.Checkbox(Languages.GatheringTab_ShowFishAddedToGuideMessages, ref showCaughtFish))        {            configuration.ShowCaughtFish = showCaughtFish;            configuration.OnSettingChanged();        }        var showMooching = configuration.ShowMooching;        if (ImGui.Checkbox(Languages.GatheringTab_ShowMooching, ref showMooching))        {            configuration.ShowMooching = showMooching;            configuration.OnSettingChanged();        }        var showMeasuringIlms = configuration.ShowMeasuringIlms;        if (ImGui.Checkbox(Languages.GatheringTab_ShowFishSizeMessages, ref showMeasuringIlms))        {            configuration.ShowMeasuringIlms = showMeasuringIlms;            configuration.OnSettingChanged();        }        var showCurrentFishingHole = configuration.ShowCurrentFishingHole;        if (ImGui.Checkbox(Languages.GatheringTab_ShowFishingHoleName,                ref showCurrentFishingHole))        {            configuration.ShowCurrentFishingHole = showCurrentFishingHole;            configuration.OnSettingChanged();        }        var showDiscoveredFishingHole = configuration.ShowDiscoveredFishingHole;        if (ImGui.Checkbox(Languages.GatheringTab_ShowFishingHoleDiscovered,                ref showDiscoveredFishingHole))        {            configuration.ShowDiscoveredFishingHole = showDiscoveredFishingHole;            configuration.OnSettingChanged();        }        var showLureMessages = configuration.ShowLureMessages;        if (ImGui.Checkbox(Languages.GatheringTab_ShowLureMessages, ref showLureMessages))        {            configuration.ShowLureMessages = showLureMessages;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.GatheringTab_ShowLureMessagesHelpMarker);        var showFishingFlavorText = configuration.ShowFishingFlavorText;        if (ImGui.Checkbox(Languages.GatheringTab_ShowFishingFlavorText, ref showFishingFlavorText))        {            configuration.ShowFishingFlavorText = showFishingFlavorText;            configuration.OnSettingChanged();        }        ImGuiComponents.HelpMarker(Languages.GatheringTab_ShowFishingFlavorTextHelpMarker);    }    private static void DrawElementalShards(Configuration configuration)    {        var hideObtainedShards = configuration.HideObtainedShards;        if (ImGui.Checkbox(Languages.GatheringTab_ShowElementalShardsCrystalsClustersMessages,                ref hideObtainedShards))        {            configuration.HideObtainedShards = hideObtainedShards;            configuration.OnSettingChanged();        }        UiHelp.ObtainedFilterMarker(Languages.GatheringTab_ShowElementalShardsCrystalsClustersMessagesHelpMarker);    }    private static void DrawStellarMissions(Configuration configuration)    {        ImGui.TextWrapped(Languages.GatheringTab_StellarSectionFilteringNote);        ImGui.Spacing();        var showStellarMissionMessages = configuration.ShowStellarMissionMessages;        if (ImGui.Checkbox(Languages.GatheringTab_ShowStellarMissionMessages,                ref showStellarMissionMessages))        {            configuration.ShowStellarMissionMessages = showStellarMissionMessages;            configuration.OnSettingChanged();        }        UiHelp.SystemFilterMarker(Languages.GatheringTab_ShowStellarMissionMessagesHelpMarker);        SettingsTabLayout.DrawNestedOptions(configuration.ShowStellarMissionMessages, () =>        {            var showStellarExecute = configuration.ShowStellarAbleToExecute;            if (ImGui.Checkbox(Languages.GatheringTab_ShowStellarAbleToExecute, ref showStellarExecute))            {                configuration.ShowStellarAbleToExecute = showStellarExecute;                configuration.OnSettingChanged();            }            UiHelp.SystemFilterMarker(Languages.GatheringTab_ShowStellarAbleToExecuteHelpMarker);            var showStellarBuff = configuration.ShowStellarBuffEffectGain;            if (ImGui.Checkbox(Languages.GatheringTab_ShowStellarBuffEffectGain, ref showStellarBuff))            {                configuration.ShowStellarBuffEffectGain = showStellarBuff;                configuration.OnSettingChanged();            }            UiHelp.SystemFilterMarker(Languages.GatheringTab_ShowStellarBuffEffectGainHelpMarker);        });        SettingsTabLayout.DrawIndependentOptions(() =>        {            var showCosmicExplorationMessages = configuration.ShowCosmicExplorationMessages;            if (ImGui.Checkbox(Languages.GatheringTab_ShowCosmicExplorationMessages,                    ref showCosmicExplorationMessages))            {                configuration.ShowCosmicExplorationMessages = showCosmicExplorationMessages;                configuration.OnSettingChanged();            }            UiHelp.SystemFilterMarker(Languages.GatheringTab_ShowCosmicExplorationMessagesHelpMarker);            var showCosmicRewards = configuration.ShowCosmicRewards;            if (ImGui.Checkbox(Languages.GatheringTab_ShowCosmicRewards, ref showCosmicRewards))            {                configuration.ShowCosmicRewards = showCosmicRewards;                configuration.OnSettingChanged();            }            UiHelp.SystemFilterMarker(Languages.GatheringTab_ShowCosmicRewardsHelpMarker);            var showCosmicContainers = configuration.ShowCosmicContainers;            if (ImGui.Checkbox(Languages.GatheringTab_ShowCosmicContainers, ref showCosmicContainers))            {                configuration.ShowCosmicContainers = showCosmicContainers;                configuration.OnSettingChanged();            }            UiHelp.SystemFilterMarker(Languages.GatheringTab_ShowCosmicContainersHelpMarker);            var showCosmicClassPointsAndDataset = configuration.ShowCosmicClassPointsAndDataset;            if (ImGui.Checkbox(Languages.GatheringTab_ShowCosmicClassPointsAndDataset,                    ref showCosmicClassPointsAndDataset))            {                configuration.ShowCosmicClassPointsAndDataset = showCosmicClassPointsAndDataset;                configuration.OnSettingChanged();            }            UiHelp.SystemFilterMarker(Languages.GatheringTab_ShowCosmicClassPointsAndDatasetHelpMarker);            var showCosmicDailyProgress = configuration.ShowCosmicDailyProgress;            if (ImGui.Checkbox(Languages.GatheringTab_ShowCosmicDailyProgress,                    ref showCosmicDailyProgress))            {                configuration.ShowCosmicDailyProgress = showCosmicDailyProgress;                configuration.OnSettingChanged();            }            UiHelp.SystemFilterMarker(Languages.GatheringTab_ShowCosmicDailyProgressHelpMarker);        });    }}
